              <div style={{display:"flex",alignItems:"baseline",gap:10,marginBottom:5}}>
                <span style={{fontFamily:"'Cinzel',serif",fontSize:"1.8rem",color:T.goldD,fontWeight:700}}>₹{product.price.toLocaleString()}</span>
